// Flatten and clean each ticket for storage
const raw = $input.all();
const tickets = raw[0].json.data || [];

return tickets.map(t => {
  const created = new Date(t.createdTime);
  const closed  = t.closedTime ? new Date(t.closedTime) : null;
  const resolutionHours = closed
    ? ((closed - created) / 36e5).toFixed(2)
    : null;

  return {
    json: {
      ticket_id:          t.id,
      ticket_number:      t.ticketNumber,
      subject:            t.subject,
      status:             t.status,
      priority:           t.priority,
      channel:            t.channel,
      department_id:      t.departmentId,
      assignee_id:        t.assigneeId,
      created_date:       created.toISOString().split('T')[0],
      created_time:       t.createdTime,
      closed_time:        t.closedTime || '',
      resolution_hours:   resolutionHours,
      first_response_time: t.responseTime || '',
      is_overdue:         t.isOverDue ? 'Yes' : 'No',
      sla_id:             t.slaId || '',
      sync_date:          new Date().toISOString().split('T')[0]
    }
  };
});

// Check if any rows in the Sheet are older than 365 days
// This node just sets the threshold date as a variable
const cutoff = new Date();
cutoff.setFullYear(cutoff.getFullYear() - 1);
return [{ json: { archive_cutoff: cutoff.toISOString().split('T')[0] } }];

// Convert old rows to CSV string (Parquet conversion happens in Python)
// n8n sends this CSV to Drive; Python converts to Parquet separately
const rows = $input.all().map(i => i.json);
if (!rows.length) return [];

const headers = Object.keys(rows[0]);
const csv = [
  headers.join(','),
  ...rows.map(r =>
    headers.map(h => {
      const v = String(r[h] ?? '').replace(/"/g, '""');
      return v.includes(',') || v.includes('\n') || v.includes('"') ? `"${v}"` : v;
    }).join(',')
  )
].join('\n');

const year = rows[0].created_date.substring(0, 4);
return [{ json: { csv_content: csv, archive_year: year, filename: `zoho_tickets_${year}.csv` } }];
